$('#soxlTradeForm').addEventListener('submit', (event) => { event.preventDefault(); const soxl = state.investments.soxl; const type = $('#soxlTradeType').value; const shares = investmentNumber($('#soxlTradeShares').value); const price = investmentNumber($('#soxlTradePrice').value); const amount = shares * price; if (!shares || !price) return; const previousShares = investmentNumber(soxl.shares); if (type === 'buy') { soxl.averagePrice = previousShares + shares ? ((previousShares * investmentNumber(soxl.averagePrice)) + amount) / (previousShares + shares) : 0; soxl.shares = previousShares + shares; soxl.cash = investmentNumber(soxl.cash) - amount; soxl.purchaseAmount = investmentNumber(soxl.purchaseAmount) + amount; } else { if (shares > previousShares) { alert('현재 보유 수량보다 많이 매도할 수 없어요.'); return; } soxl.shares = previousShares - shares; soxl.cash = investmentNumber(soxl.cash) + amount; if (!soxl.shares) soxl.averagePrice = 0; } soxl.valuation = investmentNumber(soxl.shares) * price; soxl.trades.unshift({ id: createGoalId(), date: $('#soxlTradeDate').value, type, shares, price, amount, note: $('#soxlTradeNote').value.trim() }); snapshotSoxl(`${$('#soxlTradeDate').value}T12:00:00`); persist(); render(); $('#soxlTradeDialog').close(); });
$('#vrCycleForm').addEventListener('submit', (event) => { event.preventDefault(); const vr = state.investments.tqqqVr; const mode = vr.mode || 'installment'; const flowAmount = mode === 'lump-sum' ? 0 : investmentNumber($('#vrFlowAmount').value); if (mode === 'installment') vr.contribution = flowAmount; if (mode === 'withdrawal') vr.withdrawal = flowAmount; const existing = editingVrCycleId ? vr.cycles.find((item) => item.id === editingVrCycleId) : null; const cycle = { id: existing?.id || createGoalId(), date: $('#vrCycleDate').value, targetValue: investmentNumber($('#vrTargetValue').value), gValue: investmentNumber($('#vrGValue').value), lowerBand: investmentNumber($('#vrLowerBand').value), upperBand: investmentNumber($('#vrUpperBand').value), pool: investmentNumber($('#vrPool').value), shares: investmentNumber($('#vrShares').value), averagePrice: investmentNumber($('#vrAveragePrice').value), currentPrice: investmentNumber($('#vrCurrentPrice').value), flowAmount, note: $('#vrCycleNote').value.trim() }; if (existing) vr.cycles[vr.cycles.findIndex((item) => item.id === existing.id)] = cycle; else vr.cycles.push(cycle); persist(); render(); $('#vrCycleDialog').close(); });
$('#vrTradeForm').addEventListener('submit', (event) => { event.preventDefault(); const cycle = currentVrCycle(); if (!cycle) return; const type = $('#vrTradeType').value; const shares = investmentNumber($('#vrTradeShares').value); const price = investmentNumber($('#vrTradePrice').value); if (!shares || !price) return; const position = calculateVrPosition(cycle); if (type === 'sell' && shares > position.shares) { alert('현재 보유 수량보다 많이 매도할 수 없어요.'); return; } cycle.currentPrice = price; cycle.priceUpdatedAt = $('#vrTradeDate').value; state.investments.tqqqVr.trades.push({ id: createGoalId(), cycleId: cycle.id, date: $('#vrTradeDate').value, type, shares, price, note: $('#vrTradeNote').value.trim() }); persist(); render(); $('#vrTradeDialog').close(); });
